rss.channel:
Destockage Alimentaire Store
https://www.destockagealimentairestore.com
Grossiste en produits alimentaires déstockés

{% for p in products %}


  {{ p.id }}
  {{ p.name }}
  {{ p.seo_description or p.description }}
  https://www.destockagealimentairestore.com/product/{{ p.id }}
  https://www.destockagealimentairestore.com/static/images/{{ p.images[0] if p.images is defined and p.images|length > 0 else 'default.jpg' }}
  {{ "%.2f"|format(p.price) }} EUR


    {% if p.stock is defined and p.stock > 0 %}
      in stock
    {% else %}
      out of stock
    {% endif %}



    {% if p.details is defined and p.details.marque is defined %}
      {{ p.details.marque }}
    {% else %}
      Marque inconnue
    {% endif %}


  new


    {% if p.category is string %}
      {{ p.category }}
    {% else %}
      {{ p.category | join(', ') }}
    {% endif %}



{% endfor %}
